class Solution:
    def numFriendRequests(self, ages):
        n = len(ages)
        total = 0
        for x in range(n):
            for y in range(n):
                if x == y:
                    continue
                ax, ay = ages[x], ages[y]
                if ay <= 0.5 * ax + 7:
                    continue
                if ay > ax:
                    continue
                if ay > 100 and ax < 100:
                    continue
                total += 1
        return total

solutions.python:
class Solution:
    def numFriendRequests(self, ages):
        count = [0] * 121
        for a in ages:
            count[a] += 1
        total = 0
        for ax in range(1, 121):
            if count[ax] == 0:
                continue
            for ay in range(1, 121):
                if count[ay] == 0:
                    continue
                if ay <= 0.5 * ax + 7:
                    continue
                if ay > ax:
                    continue
                if ay > 100 and ax < 100:
                    continue
                if ax == ay:
                    total += count[ax] * (count[ax] - 1)
                else:
                    total += count[ax] * count[ay]
        return total

