var numFriendRequests = function(ages) {
    const count = new Array(121).fill(0);
    for (const a of ages) count[a]++;
    let total = 0;
    for (let ax = 1; ax <= 120; ax++) {
        if (count[ax] === 0) continue;
        for (let ay = 1; ay <= 120; ay++) {
            if (count[ay] === 0) continue;
            if (ay <= 0.5 * ax + 7) continue;
            if (ay > ax) continue;
            if (ay > 100 && ax < 100) continue;
            if (ax === ay) total += count[ax] * (count[ax] - 1);
            else total += count[ax] * count[ay];
        }
    }
    return total;
};
